     * Connects to the local heritage database to fetch Manx folk tales.
     * @param taleId the unique identifier of the tale to retrieve
     * @return a JSON object containing the tale in Manx and English
     * @throws TaleNotFoundException if the taleId doesn't exist
     */
    public String fetchManxTale(int taleId) throws TaleNotFoundException {
        // Load the tale from the database
        String taleJson = database.query("SELECT * FROM manx_tales WHERE id = " + taleId);

        if (taleJson == null) {
            throw new TaleNotFoundException("Cha row yn skeeal shen ry-gheddyn agh yn çhengey veg.");
        }

        return taleJson;
    }

